"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useReducer,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import { Area } from "./parts/area";
import { CardStack } from "./parts/card-stack";
import { DragOverlay } from "./parts/drag-overlay";
import { PresetsTabs } from "./parts/presets-tabs";
import { SplitDivider } from "./parts/split-divider";
import { useBreakpoint } from "./hooks/use-breakpoint";
import { useAreaFocus } from "./hooks/use-area-focus";
import { useCornerGesture } from "./hooks/use-corner-gesture";
import { useEdgeGesture } from "./hooks/use-edge-gesture";
import { useKeyboardActions } from "./hooks/use-keyboard-actions";
import { reducer, type Action } from "./lib/reducer";
import { clampRatio } from "./lib/geometry";
import {
  computeLayout,
  flattenLeavesInOrder,
  flattenSubtreesPastDepth,
  getNodeAtPath,
  treeDepth,
  validateTree,
} from "./lib/tree";
import { makeAreaId } from "./lib/ids";
import type {
  AreaTree,
  Breakpoint,
  ResponsiveValue,
  WorkspaceProps,
} from "./types";

const DEFAULT_BREAKPOINTS = { mobile: 640, tablet: 1024 };
const DEFAULT_MIN_AREA_SIZE = { width: 120, height: 80 };
const DEFAULT_MAX_DEPTH: { mobile: number; tablet: number; desktop: number } = {
  mobile: 0,
  tablet: 3,
  desktop: 7,
};

function resolveResponsive<T>(
  value: ResponsiveValue<T> | undefined,
  breakpoint: Breakpoint,
  fallback: { mobile: T; tablet: T; desktop: T },
): T {
  if (value === undefined) return fallback[breakpoint];
  if (typeof value === "number" || typeof value === "string") {
    return value as T;
  }
  if (typeof value === "object" && value !== null) {
    const v = value as { mobile?: T; tablet?: T; desktop?: T };
    return v[breakpoint] ?? fallback[breakpoint];
  }
  return value as T;
}

function createInitialTree(defaultComponentId: string): AreaTree {
  return { kind: "leaf", id: makeAreaId(), componentId: defaultComponentId };
}

export function Workspace({
  components,
  defaultComponentId,
  layout,
  defaultLayout,
  onLayoutChange,
  presets,
  activePresetId: activePresetIdProp,
  onActivePresetChange,
  minAreaSize = DEFAULT_MIN_AREA_SIZE,
  maxSplitDepth,
  breakpoints = DEFAULT_BREAKPOINTS,
  className,
  "aria-label": ariaLabel = "Workspace",
}: WorkspaceProps) {
  const rootRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLDivElement>(null);

  const [{ tree, focusedAreaId }, dispatchInternal] = useReducer(reducer, null, () => ({
    tree: layout ?? defaultLayout ?? createInitialTree(defaultComponentId),
    focusedAreaId: null,
  }));

  // Sync controlled `layout` prop into reducer state by reference comparison.
  useEffect(() => {
    if (layout !== undefined && layout !== tree) {
      dispatchInternal({ type: "replace-tree", tree: layout });
    }
  }, [layout, tree]);

  // Fire onLayoutChange when tree changes (excluding initial mount).
  const onLayoutChangeRef = useRef(onLayoutChange);
  useEffect(() => {
    onLayoutChangeRef.current = onLayoutChange;
  }, [onLayoutChange]);
  const prevTreeRef = useRef(tree);
  useEffect(() => {
    if (prevTreeRef.current !== tree) {
      prevTreeRef.current = tree;
      onLayoutChangeRef.current?.(tree);
    }
  }, [tree]);

  const dispatch = useCallback<React.Dispatch<Action>>((action) => {
    dispatchInternal(action);
  }, []);

  // Active preset state — controlled if prop provided, otherwise internal.
  const [internalActivePresetId, setInternalActivePresetId] = useState<
    string | null
  >(presets && presets.length > 0 ? (presets[0]?.id ?? null) : null);
  const activePresetId =
    activePresetIdProp !== undefined
      ? activePresetIdProp
      : internalActivePresetId;

  const handlePresetChange = useCallback(
    (id: string) => {
      const preset = presets?.find((p) => p.id === id);
      if (!preset) return;
      dispatch({ type: "replace-tree", tree: preset.layout });
      if (activePresetIdProp === undefined) {
        setInternalActivePresetId(id);
      }
      onActivePresetChange?.(id);
    },
    [presets, dispatch, activePresetIdProp, onActivePresetChange],
  );

  // Validate tree once per change for unregistered component-ids etc.
  useEffect(() => {
    const componentIds = components.map((c) => c.id);
    const result = validateTree(tree, componentIds);
    if (!result.valid) {
      console.error("[workspace] invalid tree:", result.errors);
    }
  }, [tree, components]);

  // Track breakpoint via ResizeObserver on canvas.
  const breakpoint = useBreakpoint(canvasRef, breakpoints);

  const cap = resolveResponsive(maxSplitDepth, breakpoint, DEFAULT_MAX_DEPTH);

  const renderedTree = useMemo(
    () =>
      cap >= treeDepth(tree)
        ? tree
        : flattenSubtreesPastDepth(tree, Math.max(0, cap)),
    [tree, cap],
  );

  const isStacked = breakpoint === "mobile" || cap === 0;

  // Measure canvas to compute layout rects.
  const [canvasSize, setCanvasSize] = useState({ width: 0, height: 0 });
  useEffect(() => {
    const el = canvasRef.current;
    if (!el) return;
    const observer = new ResizeObserver(() => {
      setCanvasSize({ width: el.clientWidth, height: el.clientHeight });
    });
    observer.observe(el);
    setCanvasSize({ width: el.clientWidth, height: el.clientHeight });
    return () => observer.disconnect();
  }, []);

  const { leaves, dividers } = useMemo(() => {
    if (isStacked || canvasSize.width === 0 || canvasSize.height === 0) {
      return { leaves: [], dividers: [] };
    }
    return computeLayout(
      renderedTree,
      { x: 0, y: 0, width: canvasSize.width, height: canvasSize.height },
      { minSize: minAreaSize },
    );
  }, [renderedTree, canvasSize, isStacked, minAreaSize]);

  const stackedLeaves = useMemo(
    () => (isStacked ? flattenLeavesInOrder(tree) : []),
    [tree, isStacked],
  );

  const handleFocusChange = useCallback(
    (areaId: string | null) => {
      dispatch({ type: "focus", areaId });
    },
    [dispatch],
  );
  useAreaFocus(rootRef, handleFocusChange);

  const { dragState, beginCornerDrag } = useCornerGesture({
    rootRef: canvasRef,
    leaves,
    cap,
    breakpoint,
    dispatch,
    makeAreaId,
  });

  const { beginEdgeDrag, isResizing } = useEdgeGesture({
    rootRef: canvasRef,
    minAreaSize,
    dispatch,
  });

  const keyboard = useKeyboardActions({
    leaves,
    focusedAreaId,
    cap,
    dispatch,
    makeAreaId,
  });

  const handleCornerPointerDown = useCallback(
    (areaId: string, e: React.PointerEvent<HTMLDivElement>) => {
      beginCornerDrag(areaId, e.clientX, e.clientY, e.pointerId);
    },
    [beginCornerDrag],
  );

  const handleDividerPointerDown = useCallback(
    (
      splitPath: number[],
      e: React.PointerEvent<HTMLDivElement>,
    ) => {
      const node = getNodeAtPath(renderedTree, splitPath);
      if (node.kind !== "split") return;
      const canvas = canvasRef.current;
      if (!canvas) return;
      const rootRect = canvas.getBoundingClientRect();
      // Compute the bounds of the parent split based on its children's union
      // by re-using leaf rects: find leaves descending from this split.
      const parentRect = computeLayoutBoundsForPath(
        renderedTree,
        splitPath,
        canvasSize,
        minAreaSize,
      );
      if (!parentRect) return;
      // adjust to client coords for startClient (we use clientX/clientY)
      void rootRect;
      beginEdgeDrag(
        splitPath,
        node.orientation,
        parentRect,
        node.ratio,
        e.clientX,
        e.clientY,
        e.pointerId,
      );
    },
    [renderedTree, canvasSize, minAreaSize, beginEdgeDrag],
  );

  const handleAreaSelectComponent = useCallback(
    (areaId: string, componentId: string) => {
      dispatch({ type: "swap", areaId, componentId });
    },
    [dispatch],
  );

  const handleStackedSelectComponent = useCallback(
    (areaId: string, componentId: string) => {
      dispatch({ type: "swap", areaId, componentId });
    },
    [dispatch],
  );

  // Keyboard shortcut: Alt+Shift+Arrow to resize boundary in that direction.
  useEffect(() => {
    if (isStacked) return;
    const handler = (e: KeyboardEvent) => {
      if (!focusedAreaId) return;
      if (!e.altKey || !e.shiftKey) return;
      const isHorizontal = e.key === "ArrowLeft" || e.key === "ArrowRight";
      const isVertical = e.key === "ArrowUp" || e.key === "ArrowDown";
      if (!isHorizontal && !isVertical) return;
      e.preventDefault();
      // Find the relevant split divider that would resize in that direction.
      const direction =
        e.key === "ArrowRight"
          ? 1
          : e.key === "ArrowLeft"
            ? -1
            : e.key === "ArrowDown"
              ? 1
              : -1;
      const orientation = isHorizontal ? "vertical" : "horizontal";
      // Find first divider of this orientation that flanks the focused area.
      const focusedRect = leaves.find((l) => l.areaId === focusedAreaId);
      if (!focusedRect) return;
      const candidate = dividers.find((d) => {
        if (d.orientation !== orientation) return false;
        if (orientation === "vertical") {
          const onRight = Math.abs(focusedRect.x + focusedRect.width - d.x) < 1;
          const onLeft = Math.abs(focusedRect.x - d.x) < 1;
          return onLeft || onRight;
        } else {
          const onBottom =
            Math.abs(focusedRect.y + focusedRect.height - d.y) < 1;
          const onTop = Math.abs(focusedRect.y - d.y) < 1;
          return onTop || onBottom;
        }
      });
      if (!candidate) return;
      const node = getNodeAtPath(renderedTree, candidate.splitPath);
      if (node.kind !== "split") return;
      const next = Math.max(
        0.05,
        Math.min(0.95, node.ratio + keyboard.KEYBOARD_RESIZE_STEP * direction),
      );
      dispatch({ type: "resize", splitPath: candidate.splitPath, ratio: next });
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [
    isStacked,
    focusedAreaId,
    leaves,
    dividers,
    renderedTree,
    dispatch,
    keyboard.KEYBOARD_RESIZE_STEP,
  ]);

  return (
    <div
      ref={rootRef}
      role="application"
      aria-label={ariaLabel}
      className={cn(
        "relative flex h-full w-full flex-col overflow-hidden rounded-md border border-border bg-background text-foreground",
        className,
      )}
    >
      {presets && presets.length > 0 ? (
        <PresetsTabs
          presets={presets}
          activePresetId={activePresetId}
          onChange={handlePresetChange}
        />
      ) : null}
      <div
        ref={canvasRef}
        className={cn(
          "relative flex-1 overflow-hidden",
          (isResizing || dragState !== null) && "select-none",
        )}
      >
        {isStacked ? (
          <CardStack
            leaves={stackedLeaves}
            components={components}
            onSelectComponent={handleStackedSelectComponent}
          />
        ) : (
          <>
            {leaves.map((leaf) => (
              <div
                key={leaf.areaId}
                className="absolute"
                style={{
                  left: leaf.x,
                  top: leaf.y,
                  width: leaf.width,
                  height: leaf.height,
                }}
              >
                <Area
                  areaId={leaf.areaId}
                  componentId={leaf.componentId}
                  components={components}
                  width={leaf.width}
                  height={leaf.height}
                  isFocused={focusedAreaId === leaf.areaId}
                  cornerInert={leaf.depth >= cap}
                  canSplit={leaf.depth < cap}
                  mergeOptions={{
                    left: keyboard.findNeighbor(leaf.areaId, "left") !== null,
                    right: keyboard.findNeighbor(leaf.areaId, "right") !== null,
                    up: keyboard.findNeighbor(leaf.areaId, "up") !== null,
                    down: keyboard.findNeighbor(leaf.areaId, "down") !== null,
                  }}
                  onCornerPointerDown={handleCornerPointerDown}
                  onSelectComponent={(componentId) =>
                    handleAreaSelectComponent(leaf.areaId, componentId)
                  }
                  onSplitVertical={() => {
                    if (focusedAreaId !== leaf.areaId) {
                      dispatch({ type: "focus", areaId: leaf.areaId });
                    }
                    if (leaf.depth < cap) {
                      dispatch({
                        type: "split",
                        areaId: leaf.areaId,
                        orientation: "vertical",
                        newAreaId: makeAreaId(),
                      });
                    }
                  }}
                  onSplitHorizontal={() => {
                    if (focusedAreaId !== leaf.areaId) {
                      dispatch({ type: "focus", areaId: leaf.areaId });
                    }
                    if (leaf.depth < cap) {
                      dispatch({
                        type: "split",
                        areaId: leaf.areaId,
                        orientation: "horizontal",
                        newAreaId: makeAreaId(),
                      });
                    }
                  }}
                  onMergeDirection={(dir) => {
                    if (focusedAreaId !== leaf.areaId) {
                      dispatch({ type: "focus", areaId: leaf.areaId });
                    }
                    const neighbor = keyboard.findNeighbor(leaf.areaId, dir);
                    if (neighbor) {
                      dispatch({
                        type: "merge",
                        survivorId: leaf.areaId,
                        absorbedId: neighbor.areaId,
                      });
                    }
                  }}
                  onAreaPointerDown={() =>
                    dispatch({ type: "focus", areaId: leaf.areaId })
                  }
                />
              </div>
            ))}
            {dividers.map((d) => {
              const node = getNodeAtPath(renderedTree, d.splitPath);
              const ratio = node.kind === "split" ? node.ratio : 0.5;
              return (
                <SplitDivider
                  key={d.splitPath.join("-")}
                  orientation={d.orientation}
                  x={d.x}
                  y={d.y}
                  length={d.length}
                  ratioPercent={ratio * 100}
                  onPointerDown={(e) => handleDividerPointerDown(d.splitPath, e)}
                />
              );
            })}
            <DragOverlay dragState={dragState} leaves={leaves} />
          </>
        )}
      </div>
    </div>
  );
}

function computeLayoutBoundsForPath(
  tree: AreaTree,
  splitPath: number[],
  canvasSize: { width: number; height: number },
  minAreaSize: { width: number; height: number },
): { x: number; y: number; width: number; height: number } | null {
  // Walk the tree following splitPath and compute the bounds of the node at that path.
  let x = 0;
  let y = 0;
  let width = canvasSize.width;
  let height = canvasSize.height;
  let node: AreaTree = tree;
  for (const step of splitPath) {
    if (node.kind !== "split") return null;
    const total = node.orientation === "vertical" ? width : height;
    const min =
      node.orientation === "vertical" ? minAreaSize.width : minAreaSize.height;
    const r = clampRatio(node.ratio, total, min, min);
    const aSize = total * r;
    if (node.orientation === "vertical") {
      if (step === 0) {
        width = aSize;
      } else {
        x = x + aSize;
        width = total - aSize;
      }
    } else {
      if (step === 0) {
        height = aSize;
      } else {
        y = y + aSize;
        height = total - aSize;
      }
    }
    node = step === 0 ? node.a : node.b;
  }
  return { x, y, width, height };
}

export { Workspace } from "./workspace";
export { useAreaContext } from "./hooks/use-area-context";
export type {
  AreaContext,
  AreaTree,
  AreaTreeLeaf,
  AreaTreeSplit,
  Breakpoint,
  ResponsiveValue,
  SplitOrientation,
  WorkspaceComponent,
  WorkspacePreset,
  WorkspaceProps,
} from "./types";
export { meta } from "./meta";

import type { ReactNode } from "react";

export type ResponsiveValue<T> = T | { mobile?: T; tablet?: T; desktop?: T };

export type Breakpoint = "mobile" | "tablet" | "desktop";

export type WorkspaceComponent = {
  id: string;
  name: string;
  icon?: ReactNode;
  category?: string;
  render: () => ReactNode;
};

export type AreaContext = {
  areaId: string;
  width: number;
  height: number;
  isFocused: boolean;
};

export type SplitOrientation = "vertical" | "horizontal";

export type AreaTreeLeaf = {
  kind: "leaf";
  id: string;
  componentId: string;
};

export type AreaTreeSplit = {
  kind: "split";
  orientation: SplitOrientation;
  ratio: number;
  a: AreaTree;
  b: AreaTree;
};

export type AreaTree = AreaTreeLeaf | AreaTreeSplit;

export type WorkspacePreset = {
  id: string;
  name: string;
  layout: AreaTree;
};

export type WorkspaceProps = {
  components: WorkspaceComponent[];
  defaultComponentId: string;

  layout?: AreaTree;
  defaultLayout?: AreaTree;
  onLayoutChange?: (next: AreaTree) => void;

  presets?: WorkspacePreset[];
  activePresetId?: string;
  onActivePresetChange?: (id: string) => void;

  minAreaSize?: { width: number; height: number };
  maxSplitDepth?: ResponsiveValue<number>;
  breakpoints?: { mobile: number; tablet: number };

  "aria-label"?: string;
  className?: string;
};

"use client";

import { createContext, useContext } from "react";
import type { AreaContext } from "../types";

export const AreaContextContext = createContext<AreaContext | null>(null);

export function useAreaContext(): AreaContext {
  const ctx = useContext(AreaContextContext);
  if (!ctx) {
    throw new Error(
      "useAreaContext must be called inside a Workspace area's render() subtree",
    );
  }
  return ctx;
}

"use client";

import { useEffect } from "react";

export function useAreaFocus(
  rootRef: React.RefObject<HTMLElement | null>,
  onFocusChange: (areaId: string | null) => void,
) {
  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;

    const findAreaId = (el: Element | null): string | null => {
      let current: Element | null = el;
      while (current && current !== root) {
        if (current instanceof HTMLElement && current.dataset.areaId) {
          return current.dataset.areaId;
        }
        current = current.parentElement;
      }
      return null;
    };

    const handleFocusIn = (e: FocusEvent) => {
      const areaId = findAreaId(e.target as Element | null);
      onFocusChange(areaId);
    };

    const handleFocusOut = (e: FocusEvent) => {
      const next = e.relatedTarget as Element | null;
      if (!next || !root.contains(next)) {
        onFocusChange(null);
      }
    };

    root.addEventListener("focusin", handleFocusIn);
    root.addEventListener("focusout", handleFocusOut);
    return () => {
      root.removeEventListener("focusin", handleFocusIn);
      root.removeEventListener("focusout", handleFocusOut);
    };
  }, [rootRef, onFocusChange]);
}

"use client";

import { useEffect, useRef, useState } from "react";
import type { Breakpoint } from "../types";

export function useBreakpoint(
  rootRef: React.RefObject<HTMLElement | null>,
  breakpoints: { mobile: number; tablet: number },
  debounceMs = 100,
): Breakpoint {
  const [breakpoint, setBreakpoint] = useState<Breakpoint>("desktop");
  const timeoutRef = useRef<number | null>(null);

  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;

    const compute = (width: number): Breakpoint => {
      if (width < breakpoints.mobile) return "mobile";
      if (width < breakpoints.tablet) return "tablet";
      return "desktop";
    };

    const measure = () => {
      const width = el.clientWidth;
      setBreakpoint(compute(width));
    };

    measure();

    const observer = new ResizeObserver(() => {
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
      }
      timeoutRef.current = window.setTimeout(measure, debounceMs);
    });
    observer.observe(el);

    return () => {
      observer.disconnect();
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
      }
    };
  }, [rootRef, breakpoints.mobile, breakpoints.tablet, debounceMs]);

  return breakpoint;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { Action } from "../lib/reducer";
import { inferDragOrientation, pointInRect } from "../lib/geometry";
import type { LeafRect } from "../lib/geometry";
import type { SplitOrientation } from "../types";

export type CornerDragState = {
  originAreaId: string;
  startX: number;
  startY: number;
  currentX: number;
  currentY: number;
  intent:
    | { kind: "none" }
    | {
        kind: "split";
        orientation: SplitOrientation;
        position: { x: number; y: number };
      }
    | { kind: "merge"; targetAreaId: string };
};

const DRAG_THRESHOLD_PX = 4;

let inertLogged = false;

export function useCornerGesture(opts: {
  rootRef: React.RefObject<HTMLElement | null>;
  leaves: LeafRect[];
  cap: number;
  breakpoint: string;
  dispatch: React.Dispatch<Action>;
  makeAreaId: () => string;
}) {
  const { rootRef, leaves, cap, breakpoint, dispatch, makeAreaId } = opts;
  const [dragState, setDragState] = useState<CornerDragState | null>(null);
  const dragRef = useRef<CornerDragState | null>(null);
  const leavesRef = useRef(leaves);
  useEffect(() => {
    leavesRef.current = leaves;
  }, [leaves]);

  const beginCornerDrag = useCallback(
    (areaId: string, clientX: number, clientY: number, pointerId: number) => {
      const root = rootRef.current;
      if (!root) return;
      const rootRect = root.getBoundingClientRect();
      const localX = clientX - rootRect.left;
      const localY = clientY - rootRect.top;
      const initial: CornerDragState = {
        originAreaId: areaId,
        startX: localX,
        startY: localY,
        currentX: localX,
        currentY: localY,
        intent: { kind: "none" },
      };
      dragRef.current = initial;
      setDragState(initial);
      try {
        root.setPointerCapture(pointerId);
      } catch {
        // ignore — some browsers throw if pointer is not active
      }
    },
    [rootRef],
  );

  useEffect(() => {
    if (!dragState) return;
    const root = rootRef.current;
    if (!root) return;

    const computeIntent = (
      origin: LeafRect,
      currentX: number,
      currentY: number,
      startX: number,
      startY: number,
    ): CornerDragState["intent"] => {
      const dx = currentX - startX;
      const dy = currentY - startY;
      const distance = Math.hypot(dx, dy);
      if (distance < DRAG_THRESHOLD_PX) return { kind: "none" };

      if (pointInRect(currentX, currentY, origin)) {
        // SPLIT intent — gated by per-leaf depth. Splitting a leaf at depth N
        // produces children at depth N+1, so the cap rule is `origin.depth < cap`.
        if (origin.depth >= cap) {
          if (!inertLogged) {
            console.debug(
              `[workspace] split inert: leaf at depth ${origin.depth} would exceed cap ${cap} for breakpoint "${breakpoint}"`,
            );
            inertLogged = true;
          }
          return { kind: "none" };
        }
        const orientation = inferDragOrientation(
          startX,
          startY,
          currentX,
          currentY,
        );
        const position =
          orientation === "vertical"
            ? { x: currentX, y: origin.y }
            : { x: origin.x, y: currentY };
        return { kind: "split", orientation, position };
      }

      const target = leavesRef.current.find(
        (l) => l.areaId !== origin.areaId && pointInRect(currentX, currentY, l),
      );
      if (target) {
        return { kind: "merge", targetAreaId: target.areaId };
      }
      return { kind: "none" };
    };

    const handleMove = (e: PointerEvent) => {
      const current = dragRef.current;
      if (!current) return;
      const rootRect = root.getBoundingClientRect();
      const localX = e.clientX - rootRect.left;
      const localY = e.clientY - rootRect.top;
      const origin = leavesRef.current.find(
        (l) => l.areaId === current.originAreaId,
      );
      if (!origin) return;
      const intent = computeIntent(
        origin,
        localX,
        localY,
        current.startX,
        current.startY,
      );
      const next: CornerDragState = {
        ...current,
        currentX: localX,
        currentY: localY,
        intent,
      };
      dragRef.current = next;
      setDragState(next);
    };

    const handleUp = (e: PointerEvent) => {
      const current = dragRef.current;
      if (!current) {
        setDragState(null);
        return;
      }
      const intent = current.intent;
      if (intent.kind === "split") {
        dispatch({
          type: "split",
          areaId: current.originAreaId,
          orientation: intent.orientation,
          newAreaId: makeAreaId(),
        });
      } else if (intent.kind === "merge") {
        dispatch({
          type: "merge",
          survivorId: current.originAreaId,
          absorbedId: intent.targetAreaId,
        });
      }
      try {
        root.releasePointerCapture(e.pointerId);
      } catch {
        // ignore
      }
      dragRef.current = null;
      setDragState(null);
    };

    const handleCancel = () => {
      dragRef.current = null;
      setDragState(null);
    };

    root.addEventListener("pointermove", handleMove);
    root.addEventListener("pointerup", handleUp);
    root.addEventListener("pointercancel", handleCancel);
    window.addEventListener("blur", handleCancel);
    return () => {
      root.removeEventListener("pointermove", handleMove);
      root.removeEventListener("pointerup", handleUp);
      root.removeEventListener("pointercancel", handleCancel);
      window.removeEventListener("blur", handleCancel);
    };
  }, [dragState, rootRef, dispatch, makeAreaId, cap, breakpoint]);

  return { dragState, beginCornerDrag };
}

