import { useCallback } from "react";
import type { Action } from "../lib/reducer";
import type { LeafRect } from "../lib/geometry";
import { rectsShareFullEdge } from "../lib/geometry";
import type { SplitOrientation } from "../types";

const KEYBOARD_RESIZE_STEP = 0.04;

type ResizeDirection = "left" | "right" | "up" | "down";

export function useKeyboardActions(opts: {
  leaves: LeafRect[];
  focusedAreaId: string | null;
  cap: number;
  dispatch: React.Dispatch<Action>;
  makeAreaId: () => string;
}) {
  const { leaves, focusedAreaId, cap, dispatch, makeAreaId } = opts;

  const focusedLeaf = focusedAreaId
    ? (leaves.find((l) => l.areaId === focusedAreaId) ?? null)
    : null;
  const focusedCanSplit = focusedLeaf !== null && focusedLeaf.depth < cap;

  const splitFocused = useCallback(
    (orientation: SplitOrientation) => {
      if (!focusedLeaf) return;
      if (focusedLeaf.depth >= cap) return;
      dispatch({
        type: "split",
        areaId: focusedLeaf.areaId,
        orientation,
        newAreaId: makeAreaId(),
      });
    },
    [focusedLeaf, cap, dispatch, makeAreaId],
  );

  const findNeighbor = useCallback(
    (areaId: string, direction: ResizeDirection): LeafRect | null => {
      const origin = leaves.find((l) => l.areaId === areaId);
      if (!origin) return null;
      const candidates = leaves.filter((l) => l.areaId !== areaId);
      switch (direction) {
        case "right":
          return (
            candidates.find(
              (l) =>
                Math.abs(l.x - (origin.x + origin.width)) < 0.5 &&
                rectsShareFullEdge(origin, l) === "vertical",
            ) ?? null
          );
        case "left":
          return (
            candidates.find(
              (l) =>
                Math.abs(origin.x - (l.x + l.width)) < 0.5 &&
                rectsShareFullEdge(origin, l) === "vertical",
            ) ?? null
          );
        case "down":
          return (
            candidates.find(
              (l) =>
                Math.abs(l.y - (origin.y + origin.height)) < 0.5 &&
                rectsShareFullEdge(origin, l) === "horizontal",
            ) ?? null
          );
        case "up":
          return (
            candidates.find(
              (l) =>
                Math.abs(origin.y - (l.y + l.height)) < 0.5 &&
                rectsShareFullEdge(origin, l) === "horizontal",
            ) ?? null
          );
      }
    },
    [leaves],
  );

  const mergeWithNeighbor = useCallback(
    (direction: ResizeDirection) => {
      if (!focusedAreaId) return;
      const neighbor = findNeighbor(focusedAreaId, direction);
      if (!neighbor) return;
      dispatch({
        type: "merge",
        survivorId: focusedAreaId,
        absorbedId: neighbor.areaId,
      });
    },
    [focusedAreaId, findNeighbor, dispatch],
  );

  const swapToComponent = useCallback(
    (componentId: string) => {
      if (!focusedAreaId) return;
      dispatch({ type: "swap", areaId: focusedAreaId, componentId });
    },
    [focusedAreaId, dispatch],
  );

  return {
    splitFocused,
    mergeWithNeighbor,
    swapToComponent,
    findNeighbor,
    canSplit: focusedCanSplit,
    KEYBOARD_RESIZE_STEP,
  };
}

import type { SplitOrientation } from "../types";

export type Rect = {
  x: number;
  y: number;
  width: number;
  height: number;
};

export type LeafRect = Rect & {
  areaId: string;
  componentId: string;
  depth: number;
};

export type SplitDividerRect = {
  splitPath: number[];
  orientation: SplitOrientation;
  x: number;
  y: number;
  length: number;
};

export function inferDragOrientation(
  startX: number,
  startY: number,
  currentX: number,
  currentY: number,
): SplitOrientation {
  const dx = Math.abs(currentX - startX);
  const dy = Math.abs(currentY - startY);
  return dx >= dy ? "vertical" : "horizontal";
}

export function pointInRect(px: number, py: number, rect: Rect): boolean {
  return (
    px >= rect.x &&
    px <= rect.x + rect.width &&
    py >= rect.y &&
    py <= rect.y + rect.height
  );
}

export function rectsShareFullEdge(a: Rect, b: Rect): SplitOrientation | null {
  const eps = 0.5;
  const aRight = a.x + a.width;
  const aBottom = a.y + a.height;
  const bRight = b.x + b.width;
  const bBottom = b.y + b.height;

  if (Math.abs(aRight - b.x) < eps || Math.abs(bRight - a.x) < eps) {
    if (Math.abs(a.y - b.y) < eps && Math.abs(aBottom - bBottom) < eps) {
      return "vertical";
    }
  }
  if (Math.abs(aBottom - b.y) < eps || Math.abs(bBottom - a.y) < eps) {
    if (Math.abs(a.x - b.x) < eps && Math.abs(aRight - bRight) < eps) {
      return "horizontal";
    }
  }
  return null;
}

export function clampRatio(
  ratio: number,
  totalSize: number,
  minA: number,
  minB: number,
): number {
  if (totalSize <= minA + minB) return 0.5;
  const minRatio = minA / totalSize;
  const maxRatio = (totalSize - minB) / totalSize;
  return Math.max(minRatio, Math.min(maxRatio, ratio));
}

let counter = 0;

export function makeAreaId(): string {
  counter += 1;
  return `area-${Date.now().toString(36)}-${counter.toString(36)}`;
}

import type { AreaTree, SplitOrientation } from "../types";
import {
  mergeAreas,
  resizeSplit,
  splitLeaf,
  swapComponent,
} from "./tree";

export type WorkspaceState = {
  tree: AreaTree;
  focusedAreaId: string | null;
};

export type Action =
  | {
      type: "split";
      areaId: string;
      orientation: SplitOrientation;
      newAreaId: string;
    }
  | { type: "merge"; survivorId: string; absorbedId: string }
  | { type: "resize"; splitPath: number[]; ratio: number }
  | { type: "swap"; areaId: string; componentId: string }
  | { type: "focus"; areaId: string | null }
  | { type: "replace-tree"; tree: AreaTree };

export function reducer(state: WorkspaceState, action: Action): WorkspaceState {
  switch (action.type) {
    case "split": {
      const tree = splitLeaf(
        state.tree,
        action.areaId,
        action.orientation,
        action.newAreaId,
      );
      return tree === state.tree ? state : { ...state, tree };
    }
    case "merge": {
      const tree = mergeAreas(state.tree, action.survivorId, action.absorbedId);
      if (tree === state.tree) return state;
      const focusedAreaId =
        state.focusedAreaId === action.absorbedId
          ? action.survivorId
          : state.focusedAreaId;
      return { tree, focusedAreaId };
    }
    case "resize": {
      const tree = resizeSplit(state.tree, action.splitPath, action.ratio);
      return tree === state.tree ? state : { ...state, tree };
    }
    case "swap": {
      const tree = swapComponent(state.tree, action.areaId, action.componentId);
      return tree === state.tree ? state : { ...state, tree };
    }
    case "focus": {
      if (state.focusedAreaId === action.areaId) return state;
      return { ...state, focusedAreaId: action.areaId };
    }
    case "replace-tree": {
      if (action.tree === state.tree) return state;
      return { ...state, tree: action.tree };
    }
  }
}

import type {
  AreaTree,
  AreaTreeLeaf,
  AreaTreeSplit,
  SplitOrientation,
} from "../types";
import { clampRatio } from "./geometry";
import type { LeafRect, Rect, SplitDividerRect } from "./geometry";

export function findLeaf(
  tree: AreaTree,
  areaId: string,
  path: number[] = [],
): { node: AreaTreeLeaf; path: number[] } | null {
  if (tree.kind === "leaf") {
    return tree.id === areaId ? { node: tree, path } : null;
  }
  return (
    findLeaf(tree.a, areaId, [...path, 0]) ??
    findLeaf(tree.b, areaId, [...path, 1])
  );
}

export function getNodeAtPath(tree: AreaTree, path: number[]): AreaTree {
  let node: AreaTree = tree;
  for (const step of path) {
    if (node.kind !== "split") {
      throw new Error(`Invalid path: encountered leaf before path end`);
    }
    node = step === 0 ? node.a : node.b;
  }
  return node;
}

export function replaceNodeAtPath(
  tree: AreaTree,
  path: number[],
  next: AreaTree,
): AreaTree {
  if (path.length === 0) return next;
  if (tree.kind !== "split") {
    throw new Error(`Cannot descend into a leaf`);
  }
  const [head, ...rest] = path;
  if (head === 0) {
    return { ...tree, a: replaceNodeAtPath(tree.a, rest, next) };
  }
  return { ...tree, b: replaceNodeAtPath(tree.b, rest, next) };
}

export function splitLeaf(
  tree: AreaTree,
  areaId: string,
  orientation: SplitOrientation,
  newAreaId: string,
): AreaTree {
  const found = findLeaf(tree, areaId);
  if (!found) return tree;
  const { node, path } = found;
  const split: AreaTreeSplit = {
    kind: "split",
    orientation,
    ratio: 0.5,
    a: node,
    b: { kind: "leaf", id: newAreaId, componentId: node.componentId },
  };
  return replaceNodeAtPath(tree, path, split);
}

export function mergeAreas(
  tree: AreaTree,
  survivorId: string,
  absorbedId: string,
): AreaTree {
  const survivor = findLeaf(tree, survivorId);
  const absorbed = findLeaf(tree, absorbedId);
  if (!survivor || !absorbed) return tree;
  if (survivor.path.length === 0 || absorbed.path.length === 0) return tree;
  const survivorParent = survivor.path.slice(0, -1);
  const absorbedParent = absorbed.path.slice(0, -1);
  if (
    survivorParent.length !== absorbedParent.length ||
    !survivorParent.every((step, i) => step === absorbedParent[i])
  ) {
    return tree;
  }
  return replaceNodeAtPath(tree, survivorParent, survivor.node);
}

export function resizeSplit(
  tree: AreaTree,
  splitPath: number[],
  ratio: number,
): AreaTree {
  const node = getNodeAtPath(tree, splitPath);
  if (node.kind !== "split") return tree;
  return replaceNodeAtPath(tree, splitPath, { ...node, ratio });
}

export function swapComponent(
  tree: AreaTree,
  areaId: string,
  componentId: string,
): AreaTree {
  const found = findLeaf(tree, areaId);
  if (!found) return tree;
  return replaceNodeAtPath(tree, found.path, {
    ...found.node,
    componentId,
  });
}

export function treeDepth(tree: AreaTree): number {
  if (tree.kind === "leaf") return 0;
  return 1 + Math.max(treeDepth(tree.a), treeDepth(tree.b));
}

export function flattenLeavesInOrder(tree: AreaTree): AreaTreeLeaf[] {
  if (tree.kind === "leaf") return [tree];
  return [...flattenLeavesInOrder(tree.a), ...flattenLeavesInOrder(tree.b)];
}

export function flattenSubtreesPastDepth(
  tree: AreaTree,
  cap: number,
  currentDepth = 0,
): AreaTree {
  if (tree.kind === "leaf") return tree;
  if (currentDepth >= cap) {
    return collapseToFirstLeaf(tree);
  }
  return {
    ...tree,
    a: flattenSubtreesPastDepth(tree.a, cap, currentDepth + 1),
    b: flattenSubtreesPastDepth(tree.b, cap, currentDepth + 1),
  };
}

function collapseToFirstLeaf(tree: AreaTree): AreaTreeLeaf {
  if (tree.kind === "leaf") return tree;
  return collapseToFirstLeaf(tree.a);
}

export function validateTree(
  tree: AreaTree,
  registeredComponentIds: string[],
): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  const seenIds = new Set<string>();
  const registered = new Set(registeredComponentIds);

  function walk(node: AreaTree) {
    if (node.kind === "leaf") {
      if (seenIds.has(node.id)) {
        errors.push(`Duplicate area id: "${node.id}"`);
      }
      seenIds.add(node.id);
      if (!registered.has(node.componentId)) {
        errors.push(
          `Leaf "${node.id}" references unregistered component "${node.componentId}"`,
        );
      }
    } else {
      if (node.ratio <= 0 || node.ratio >= 1) {
        errors.push(`Split ratio ${node.ratio} out of range (0, 1)`);
      }
      walk(node.a);
      walk(node.b);
    }
  }

  walk(tree);
  return { valid: errors.length === 0, errors };
}

type LayoutResult = {
  leaves: LeafRect[];
  dividers: SplitDividerRect[];
};

export function computeLayout(
  tree: AreaTree,
  bounds: Rect,
  options?: { minSize?: { width: number; height: number } },
): LayoutResult {
  const minW = options?.minSize?.width ?? 0;
  const minH = options?.minSize?.height ?? 0;
  const leaves: LeafRect[] = [];
  const dividers: SplitDividerRect[] = [];

  function walk(node: AreaTree, rect: Rect, depth: number, path: number[]) {
    if (node.kind === "leaf") {
      leaves.push({
        areaId: node.id,
        componentId: node.componentId,
        depth,
        ...rect,
      });
      return;
    }
    if (node.orientation === "vertical") {
      const total = rect.width;
      const r = clampRatio(node.ratio, total, minW, minW);
      const aWidth = total * r;
      const bWidth = total - aWidth;
      walk(
        node.a,
        { x: rect.x, y: rect.y, width: aWidth, height: rect.height },
        depth + 1,
        [...path, 0],
      );
      walk(
        node.b,
        {
          x: rect.x + aWidth,
          y: rect.y,
          width: bWidth,
          height: rect.height,
        },
        depth + 1,
        [...path, 1],
      );
      dividers.push({
        splitPath: path,
        orientation: "vertical",
        x: rect.x + aWidth,
        y: rect.y,
        length: rect.height,
      });
    } else {
      const total = rect.height;
      const r = clampRatio(node.ratio, total, minH, minH);
      const aHeight = total * r;
      const bHeight = total - aHeight;
      walk(
        node.a,
        { x: rect.x, y: rect.y, width: rect.width, height: aHeight },
        depth + 1,
        [...path, 0],
      );
      walk(
        node.b,
        {
          x: rect.x,
          y: rect.y + aHeight,
          width: rect.width,
          height: bHeight,
        },
        depth + 1,
        [...path, 1],
      );
      dividers.push({
        splitPath: path,
        orientation: "horizontal",
        x: rect.x,
        y: rect.y + aHeight,
        length: rect.width,
      });
    }
  }

  walk(tree, bounds, 0, []);
  return { leaves, dividers };
}

